INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (112, 'COCAINA PBC (ORINA SIMPLE) - CUALITATIVO', 'orina simple', 'INMUNOCROMATOGRAFIA', 45.00, 35.00, 'FRASCO ORINA', 'NO REQUIERE AYUNO Y/O PREPARACIÓN PREVIA. NOTA: ES RESPONSABILIDAD DE LA REFERENCIA; IDENTIFICAR Y CONSTATAR QUE LA ORINA PERTENECE AL PACIENTE. NO HABER INGERIDO MATE DE COCA 24 horas ANTES DEL nameEN. NO CONSUMIR MEDICACIÓN DEL TIPO DE ANTINFLAMATORIOS, POR LO MENOS 48 horas ANTES DEL nameEN.', '1 día', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (113, 'MARIHUANA THC (ORINA SIMPLE) - CUALITATIVO', 'orina simple', 'INMUNOCROMATOGRAFIA / MANUAL', 45.00, 35.00, 'FRASCO ORINA', 'NO REQUIERE AYUNO Y/O PREPARACIÓN PREVIA. EL PACIENTE DEBERA PRESENTARSE CON DNI EN EL CASO DE MENORES DE EDAD CON LA PERSONA RESPONSABLE CON DNI Y FIRMAR FORMATO DE CONSENTIMIENTO PARA LA PRUEBA Y COLOCAR SU HUELLA DIGITAL, MUESTRA > 20 ML. ORINA REFRIGERADO. NOTA: ES RESPONSABILIDAD DE LA REFERENCIA; IDENTIFICAR Y CONSTATAR QUE LA ORINA PERTENECE AL PACIENTE.', '1 día', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (114, 'ROTAVIRUS + ADENOVIRUS (HECES)', 'heces', 'inmunocromatografia', 50.00, 40.00, 'FRASCO CON TAPA ROSCA', 'MUESTRA FRESCA, LA QUE CONTENGA MOCO Y/O SANGRE. INFANTES: EL PAÑAL COLOCAR AL REVES, PARA EVITAR QUE EL GEL DEL PAÑAL ABSORBA LOS LIQUIDOS O QUE LAS HECES SE IMPREGNEN. REFRIGERAR, EN EL CASO DE NO ENVIAR INMEDIATAMENTE.', '1 día', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (115, 'bk esputo directo', 'varios', 'microscopia manual', 35.00, 15.00, 'FRASCO CON TAPA ROSCA', 'NO REQUIERE DE PREPARACION PREVIA SEGÚN EL TIPO DE MUESTRA. SE SUGIERE OBTENER LA MUESTRA DE ESPUTO MUY TEMPRANO AL LEVANTARSE, ANTES DE CEPILLARSE LOS DIENTES, ANTES DE ENJUAGARSE LA BOCA Y ANTES DE INGERIR ALIMENTOS. SE DEBE RECOLECTAR LA EXPECTORACION BRONQUIAL,SIN SALIVA.', '1 día', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (116, 'cultivo de secrecion vaginal', 'secrecion vaginal', 'CULTIVO / MICROSCOPIA / MANUAL', 50.00, 25.00, 'MEDIO DE TRANSPORTE', 'NO ANTIBIÓICOS, NI OVULOS 3 DIAS ANTES DEL EXÁMEN Y SIN ASEO PREVIO, MEDIO DE TRANSPORTE + 02 LAMINAS (FROTIS) INCLUYE : nameEN DIRECTO + ANTIBIOGRAMA', '3 dias', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (117, 'cultivo herida', 'herida', 'CULTIVO / MICROSCOPIA / MANUAL', 50.00, 25.00, 'MEDIO DE TRANSPORTE', 'NO ANTIBIÓTICOS 3 DIAS ANTES DE LA PRUEBA, NI APLICACIÓN DE ANTISEPTICAS. HERIDAS: SI ES NECESARIO LIMPIAR CON SUERO FISIOLOG. Y/O TOMAR LA MUESTRA DE LA PARTE INTERNA DE LA HERIDA. (MEDIO DE TRANSPORTE + 02 LAMINAS (FROTIS) ) ASPIRADOS: ENVIAR LA MUESTRA EN EL MISMO FRASCO O JERINGA QUE SE TOMÓ. NOTA: ES IMPORTANTE QUE SE INDIQUE LA UBICACIÓN Y TIPO DE MUESTRA QUE SE TOME EN LA ORDEN O TICKET. TIEMPO DE RESPUESTA NO SE INCLUYE DOMINGOS NI FERIADOS.', '3 dias', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (118, 'hemocultivo con removedor de antibiotico', 'sangre total', 'CULTIVO / MICROSCOPIA / MANUAL', 90.00, 80.00, 'frasco hemocultivo con removedor de antibiotico', 'DE PREFERENCIA NO ANTIBIOTICOS, 03 DIAS PREVIOS AL nameEN. REVISAR SOLICITUD MÉDICA Y PRECISAR LUGAR DE PUNCIÓN EN EL FRASCO DE HEMOCULTIVO. INCLUYE REMOVEDOR DE ATB, MEDIO ADULTOS: 5-10 ML DE SANGRE TOTAL (VENOSA), MEDIO PEDIATRICO: INFANTES: 1-2 ML Y NIÑOS: 3-5 ML DE SANGRE TOTAL (VENOSA).', '7 dias', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
