INSERT INTO laboratory_tests (id, name, sample, method, price_public, price_convenio, tube, info, process_time, quantity, active) VALUES (132, 'cultivo de hongos', 'una, piel, cuero cabelludo, orina', 'cultivo/microscopia/manual', 60.00, 40.00, 'placa petri pequeña', 'NO ANTIMICÓTICOS (ORALES, CREMAS O SOLUCIONES) POR 03 DIAS ANTES DE LA PRUEBA, NO ASEO DE LA ZONA AFECTADA. EN CULTIVOS DE UÑAS, DEJAR QUE ESTAS CREZCAN PARA LA OBTENCIÓN DE UNA MEJOR MUESTRA. EN EL CASO DE AUSENCIA O ESCASAS ESCAMAS (PIEL), ENVIAR EL BISTURÍ CON EL CUAL SE HIZO EL RASPADO. INDICAR LA ZONA AFECTADA Y EL TIPO DE MUESTRA EN LA ORDEN O TICKET.', '7 dias', 1, 1) ON DUPLICATE KEY UPDATE name = VALUES(name), sample = VALUES(sample), method = VALUES(method), price_public = VALUES(price_public), price_convenio = VALUES(price_convenio), tube = VALUES(tube), info = VALUES(info), process_time = VALUES(process_time), quantity = VALUES(quantity), active = VALUES(active), updated_at = CURRENT_TIMESTAMP;
